mapper.sql:
from aiw_system_config c
where 1 = 1

    and c.config_group = #{criteria.configGroup}


    and (
        c.config_key like concat('%', #{criteria.keyword}, '%')
        or c.description like concat('%', #{criteria.keyword}, '%')
    )


    and c.environment = #{criteria.environment}


    and c.status = #{criteria.status}

mapper.select:
select *
from aiw_system_config
where config_group = #{configGroup}
  and config_key = #{configKey}
  and environment = #{environment}
  and status = 'ENABLED'
limit 1

select *
from aiw_system_config
where config_group = #{configGroup}
  and config_key = #{configKey}
  and environment = #{environment}
limit 1

select c.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
